UPDATE app_team_user
team_id = #{team_id}, user_id = #{user_id}, join_type = #{join_type}, status = #{status}, team_role = #{team_role}, join_time = #{join_time},
WHERE id = #{id};

mapper.select:
SELECT
,team_id.id as team_id_id1 ,team_id.team_name as team_id_team_name1 ,team_id.creator_id as team_id_creator_id1 ,team_id.admin_id as team_id_admin_id1 ,team_id.description as team_id_description1 ,team_id.status as team_id_status1 ,team_id.create_time as team_id_create_time1 ,team_id.update_time as team_id_update_time1 ,su.user_id as user_id_id1 ,COALESCE(NULLIF(TRIM(IFNULL(app_u.nickname,'')),''), app_u.username, sys_u.NAME, sys_u.USERNAME, CONCAT('用户ID:', CAST(su.user_id AS CHAR))) as user_id_team_name1 ,COALESCE(app_u.username, sys_u.USERNAME) as user_id_username1 ,sys_u.role_manage_id as user_id_role_manage_id1 ,IFNULL(app_u.account_status,'1') as user_id_status1 ,sys_u.create_time as user_id_create_time1 ,sys_u.update_time as user_id_update_time1 FROM app_team_user su left join app_team team_id on team_id.id=su.team_id left join app_user app_u on CAST(app_u.id AS CHAR)=TRIM(CAST(IFNULL(su.user_id,'') AS CHAR)) left join sys_user sys_u on CAST(sys_u.id AS CHAR)=TRIM(CAST(IFNULL(su.user_id,'') AS CHAR)) where 1 = 1 and su.id = #{id} and su.team_id = #{team_id} and su.user_id = #{user_id} and su.join_type = #{join_type} and su.status = #{status} and su.team_role = #{team_role} and su.join_time = #{join_time}
and ( CAST(su.user_id AS CHAR)=CAST(#{login_user_id} AS CHAR) or CAST(su.team_id AS CHAR) in ( SELECT CAST(t.id AS CHAR) FROM app_team t WHERE CAST(t.admin_id AS CHAR)=CAST(#{login_user_id} AS CHAR) OR CAST(t.creator_id AS CHAR)=CAST(#{login_user_id} AS CHAR) ) or CAST(su.team_id AS CHAR) in ( SELECT CAST(tu.team_id AS CHAR) FROM app_team_user tu WHERE CAST(tu.user_id AS CHAR)=CAST(#{login_user_id} AS CHAR) AND CAST(IFNULL(tu.status,'') AS CHAR)='1' ) )

SELECT
,team_id.id as team_id_id1 ,team_id.team_name as team_id_team_name1 ,team_id.creator_id as team_id_creator_id1 ,team_id.admin_id as team_id_admin_id1 ,team_id.description as team_id_description1 ,team_id.status as team_id_status1 ,team_id.create_time as team_id_create_time1 ,team_id.update_time as team_id_update_time1 ,su.user_id as user_id_id1 ,COALESCE(NULLIF(TRIM(IFNULL(app_u.nickname,'')),''), app_u.username, sys_u.NAME, sys_u.USERNAME, CONCAT('用户ID:', CAST(su.user_id AS CHAR))) as user_id_team_name1 ,COALESCE(app_u.username, sys_u.USERNAME) as user_id_username1 ,sys_u.role_manage_id as user_id_role_manage_id1 ,IFNULL(app_u.account_status,'1') as user_id_status1 ,sys_u.create_time as user_id_create_time1 ,sys_u.update_time as user_id_update_time1 FROM app_team_user su left join app_team team_id on team_id.id=su.team_id left join app_user app_u on CAST(app_u.id AS CHAR)=TRIM(CAST(IFNULL(su.user_id,'') AS CHAR)) left join sys_user sys_u on CAST(sys_u.id AS CHAR)=TRIM(CAST(IFNULL(su.user_id,'') AS CHAR)) where 1 = 1 and su.id = #{pd.id} and su.team_id = #{pd.team_id} and su.user_id = #{pd.user_id} and su.join_type = #{pd.join_type} and su.status = #{pd.status} and su.team_role = #{pd.team_role} and su.join_time = #{pd.join_time}
and ( CAST(su.user_id AS CHAR)=CAST(#{pd.login_user_id} AS CHAR) or CAST(su.team_id AS CHAR) in ( SELECT CAST(t.id AS CHAR) FROM app_team t WHERE CAST(t.admin_id AS CHAR)=CAST(#{pd.login_user_id} AS CHAR) OR CAST(t.creator_id AS CHAR)=CAST(#{pd.login_user_id} AS CHAR) ) or CAST(su.team_id AS CHAR) in ( SELECT CAST(tu.team_id AS CHAR) FROM app_team_user tu WHERE CAST(tu.user_id AS CHAR)=CAST(#{pd.login_user_id} AS CHAR) AND CAST(IFNULL(tu.status,'') AS CHAR)='1' ) )
